// Generate realistic gameplay anomaly data
const anomalyTypes = ['speed_hack', 'aim_bot', 'wall_hack', 'resource_exploit', 'suspicious_pattern'];
const playerNames = ['Player_Alpha', 'Player_Beta', 'Player_Gamma', 'Player_Delta', 'Player_Epsilon'];

// Generate 5 anomaly records
const anomalies = [];

for (let i = 0; i < 5; i++) {
  const anomalyType = anomalyTypes[Math.floor(Math.random() * anomalyTypes.length)];
  const playerId = `PID_${Math.floor(Math.random() * 10000)}`;
  const playerName = playerNames[Math.floor(Math.random() * playerNames.length)];

  // Generate severity score based on anomaly type
  let severityScore;
  if (anomalyType === 'aim_bot' || anomalyType === 'speed_hack') {
    severityScore = Math.floor(Math.random() * 30) + 70; // 70-100 (high)
  } else if (anomalyType === 'wall_hack') {
    severityScore = Math.floor(Math.random() * 20) + 60; // 60-80 (medium-high)
  } else if (anomalyType === 'resource_exploit') {
    severityScore = Math.floor(Math.random() * 30) + 50; // 50-80 (medium)
  } else {
    severityScore = Math.floor(Math.random() * 40) + 30; // 30-70 (low-medium)
  }

  const anomaly = {
    player_id: playerId,
    player_name: playerName,
    anomaly_type: anomalyType,
    severity_score: severityScore,
    timestamp: new Date(Date.now() - Math.floor(Math.random() * 3600000)).toISOString(),
    game_session: {
      session_id: `SESSION_${Math.floor(Math.random() * 100000)}`,
      duration_minutes: Math.floor(Math.random() * 120) + 10,
      map: ['Desert_Storm', 'Urban_Warfare', 'Forest_Ops', 'Arctic_Base'][Math.floor(Math.random() * 4)],
      game_mode: ['Team_Deathmatch', 'Capture_Flag', 'Battle_Royale', 'Domination'][Math.floor(Math.random() * 4)]
    },
    player_statistics: {
      kills: Math.floor(Math.random() * 50) + (anomalyType === 'aim_bot' ? 30 : 0),
      deaths: Math.floor(Math.random() * 20) + 1,
      accuracy_percentage: anomalyType === 'aim_bot' ? Math.floor(Math.random() * 10) + 90 : Math.floor(Math.random() * 40) + 30,
      headshot_percentage: anomalyType === 'aim_bot' ? Math.floor(Math.random() * 20) + 70 : Math.floor(Math.random() * 30) + 10,
      distance_traveled: Math.floor(Math.random() * 10000) + (anomalyType === 'speed_hack' ? 15000 : 1000),
      resources_collected: Math.floor(Math.random() * 500) + (anomalyType === 'resource_exploit' ? 2000 : 0)
    },
    behavioral_metrics: {
      movement_speed_avg: anomalyType === 'speed_hack' ? Math.floor(Math.random() * 50) + 150 : Math.floor(Math.random() * 30) + 80,
      reaction_time_ms: anomalyType === 'aim_bot' ? Math.floor(Math.random() * 30) + 10 : Math.floor(Math.random() * 100) + 150,
      wall_penetration_shots: anomalyType === 'wall_hack' ? Math.floor(Math.random() * 20) + 15 : Math.floor(Math.random() * 3),
      suspicious_actions_count: Math.floor(Math.random() * 10) + (severityScore > 70 ? 15 : 0),
      pattern_deviation_score: Math.floor(Math.random() * 100),
      previous_violations: Math.floor(Math.random() * 5)
    },
    detection_confidence: Math.floor(Math.random() * 20) + 80,
    server_region: ['US-East', 'US-West', 'EU-Central', 'Asia-Pacific'][Math.floor(Math.random() * 4)]
  };

  anomalies.push(anomaly);
}

return anomalies.map(anomaly => ({ json: anomaly }));

